<script setup lang="ts">/* TextSplitNode — 文本分段 */import { computed } from 'vue';import { Handle, Position } from '@vue-flow/core';import { useCanvasStore } from '@/stores/canvasStore'
const p=defineProps<{id:string;data:any;selected?:boolean}>();const cs=useCanvasStore();const d=computed(()=>p.data||{})
const m=computed({get:()=>d.value.splitMode||'line',set:v=>cs.updateNodeData(p.id,{splitMode:v})})
const s=computed({get:()=>d.value.separator||'',set:v=>cs.updateNodeData(p.id,{separator:v})})
function run(){window.dispatchEvent(new CustomEvent('jc-canvas-run-node',{detail:p.id}))}</script>
<template><div class="x" :class="{sel:selected}" :style="{borderColor:selected?'#fb923c':'var(--border)'}"><Handle type="target" :position="Position.Left" :style="{background:'#fb923c',width:10,height:10,border:'none'}"/><div class="xh"><div class="xi" style="background:rgba(251,146,60,.18);color:#fdba74"><span class="mso" style="font-size:13px">splitscreen</span></div><div class="xl">文本分割</div><button class="xr" :disabled="data.status==='running'" @pointerdown.stop @click.stop="run"><span class="mso">play_arrow</span></button></div><div class="xb" @mousedown.stop><select v-model="m" class="xi2"><option value="line">按行</option><option value="paragraph">按段落</option><option value="custom">自定义分隔</option><option value="storyboard">智能分镜</option><option value="markdown-heading">Markdown标题</option><option value="numbered">序号</option><option value="char-chunk">按字数</option></select><input v-if="m==='custom'||m==='char-chunk'" v-model="s" class="xi2" :placeholder="m==='char-chunk'?'字数':'分隔符'"/><div v-if="data.segmentCount" class="xs">{{data.segmentCount}} 段</div><div v-if="data.error" class="xe"><span class="mso" style="font-size:11px">error</span>{{data.error}}</div></div><Handle type="source" :position="Position.Right" :style="{background:'#fb923c',width:10,height:10,border:'none'}"/></div></template>
<style scoped>.x{width:260px;border:2px solid var(--border);border-radius:12px;background:var(--paper);box-shadow:var(--jc-shadow-sm);color:var(--ink1)}.x.sel{border-color:#fb923c}.xh{display:flex;align-items:center;gap:8px;padding:8px 12px;border-bottom:1px solid var(--border2)}.xi{width:24px;height:24px;border-radius:6px;display:flex;align-items:center;justify-content:center}.xl{flex:1;font-size:13px;font-weight:600}.xr{width:26px;height:26px;border:1px solid var(--border);border-radius:6px;background:var(--surface);color:var(--ink2);cursor:pointer;display:flex;align-items:center;justify-content:center}.xr:disabled{opacity:.4}.xb{padding:10px;display:flex;flex-direction:column;gap:6px}.xi2{width:100%;border:1px solid var(--border);border-radius:6px;background:var(--surface);color:var(--ink1);padding:5px 8px;font-size:11px;outline:none;font:inherit}.xs{font-size:11px;color:var(--ink2);padding:4px 6px;background:var(--surface);border-radius:4px}.xe{display:flex;align-items:flex-start;gap:4px;font-size:10px;color:#f87171;background:rgba(239,68,68,.1);border:1px solid rgba(239,68,68,.2);border-radius:4px;padding:4px 8px}</style>
